import{bQ as a,aL as i,u as n,G as e}from"./chunks/framework.D06dwy5q.js";const r=JSON.parse('{"title":"09a｜软件安装故障与进阶","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/09a-软件安装故障与进阶.md","filePath":"01.Linux基础/09a-软件安装故障与进阶.md","lastUpdated":null}'),t={name:"01.Linux基础/09a-软件安装故障与进阶.md"};function l(p,s,h,d,o,k){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="_09a-软件安装故障与进阶" tabindex="-1">09a｜软件安装故障与进阶 <a class="header-anchor" href="#_09a-软件安装故障与进阶" aria-label="Permalink to &quot;09a｜软件安装故障与进阶&quot;">​</a></h1><p>上一篇学会了三种安装方式。但实际装软件时会遇到各种问题：yum 报锁装不上、依赖冲突、源码编译失败、装完跑不起来。本篇讲这些故障的排查，以及一些进阶话题（动态库依赖、版本回滚、Python 多版本）。</p><h2 id="一、yum-报锁-another-app-is-holding-yum-lock" tabindex="-1">一、yum 报锁：Another app is holding yum lock <a class="header-anchor" href="#一、yum-报锁-another-app-is-holding-yum-lock" aria-label="Permalink to &quot;一、yum 报锁：Another app is holding yum lock&quot;">​</a></h2><p>装软件时报这个错，说明有另一个 yum 进程在跑（可能是系统的自动更新工具）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Existing lock /var/run/yum.pid: another copy is running as pid 12345.</span></span></code></pre></div><h3 id="排查" tabindex="-1">排查 <a class="header-anchor" href="#排查" aria-label="Permalink to &quot;排查&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第 1 步：看是谁持有锁</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ef</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 可能是 yum-cron、PackageKit、dnf-automatic 这类自动更新工具</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第 2 步：如果是自动更新工具，等它跑完</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果是异常残留的进程，清理锁</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/yum.pid</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">残留进程PI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">D</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>生产环境推荐关闭自动更新，避免它和手工安装互相阻塞：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL 系关闭 yum-cron</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum-cron</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum-cron</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或 dnf-automatic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf-automatic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf-automatic</span></span></code></pre></div><h2 id="二、依赖冲突" tabindex="-1">二、依赖冲突 <a class="header-anchor" href="#二、依赖冲突" aria-label="Permalink to &quot;二、依赖冲突&quot;">​</a></h2><p>装 A 依赖 B 的旧版，装 C 依赖 B 的新版，两个需求打架，就是依赖冲突。表现通常是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packageA</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Error: Package: packageA requires libfoo.so.2, but libfoo-1.x is installed</span></span></code></pre></div><h3 id="排查-1" tabindex="-1">排查 <a class="header-anchor" href="#排查-1" aria-label="Permalink to &quot;排查&quot;">​</a></h3><p>先看两个包分别来自哪个仓库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> available</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libfoo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> installed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libfoo</span></span></code></pre></div><p>再看冲突方提供的是哪个版本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> provides</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libfoo.so.2</span></span></code></pre></div><h3 id="处理" tabindex="-1">处理 <a class="header-anchor" href="#处理" aria-label="Permalink to &quot;处理&quot;">​</a></h3><p>方式 1：卸载冲突方（如果它不是关键组件）。</p><p>方式 2：禁用提供冲突包的仓库后再安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packageA</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --disablerepo=epel</span></span></code></pre></div><p>严重冲突时可能需要升级或降级某个核心库，但<strong>核心库（glibc、openssl、libstdc++）的版本变动会影响全系统</strong>，操作前要评估影响。</p><h2 id="三、误删系统包导致系统损坏" tabindex="-1">三、误删系统包导致系统损坏 <a class="header-anchor" href="#三、误删系统包导致系统损坏" aria-label="Permalink to &quot;三、误删系统包导致系统损坏&quot;">​</a></h2><p>误删了 glibc、coreutils 这类基础包，会导致命令找不到、甚至无法登录。</p><h3 id="防护" tabindex="-1">防护 <a class="header-anchor" href="#防护" aria-label="Permalink to &quot;防护&quot;">​</a></h3><p>大多数包管理器会拒绝卸载受保护包。可以装保护插件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum-plugin-protect-packages</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 编辑 /etc/yum/protected.d/system.conf，列出受保护的包</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">glibc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">coreutils</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span></span></code></pre></div><h3 id="应急" tabindex="-1">应急 <a class="header-anchor" href="#应急" aria-label="Permalink to &quot;应急&quot;">​</a></h3><p>极端情况下系统已经损坏（命令找不到、无法正常启动），从其他同版本机器拷贝包文件，手动重装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用 rescue 模式或 live CD 启动</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 挂载原系统分区</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ivh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --root=/mnt/sysimage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.rpm</span></span></code></pre></div><p>或者用安装盘进 rescue 模式重装核心包。</p><h2 id="四、源码编译失败" tabindex="-1">四、源码编译失败 <a class="header-anchor" href="#四、源码编译失败" aria-label="Permalink to &quot;四、源码编译失败&quot;">​</a></h2><p>源码编译最常见的失败是缺开发库，<code>./configure</code> 或 <code>make</code> 报错。</p><h3 id="现象-1-configure-报缺库" tabindex="-1">现象 1：configure 报缺库 <a class="header-anchor" href="#现象-1-configure-报缺库" aria-label="Permalink to &quot;现象 1：configure 报缺库&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./configure: error: the HTTP rewrite module requires the PCRE library.</span></span></code></pre></div><p>根因：缺 <code>pcre-devel</code>（或 Debian 的 <code>libpcre3-dev</code>）。上一篇讲过，运行时库和开发库是分开的两个包，编译要装带 <code>-devel</code>/<code>-dev</code> 后缀的开发库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pcre-devel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libpcre3-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Debian 系</span></span></code></pre></div><h3 id="现象-2-make-报找不到头文件" tabindex="-1">现象 2：make 报找不到头文件 <a class="header-anchor" href="#现象-2-make-报找不到头文件" aria-label="Permalink to &quot;现象 2：make 报找不到头文件&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fatal error: openssl/ssl.h: No such file or directory</span></span></code></pre></div><p>根因：缺 <code>openssl-devel</code>（或 <code>libssl-dev</code>）。<code>ssl.h</code> 是头文件，只装运行时库 <code>openssl</code> 不带，要装开发库。</p><h3 id="现象-3-链接时报-undefined-symbol" tabindex="-1">现象 3：链接时报 undefined symbol <a class="header-anchor" href="#现象-3-链接时报-undefined-symbol" aria-label="Permalink to &quot;现象 3：链接时报 undefined symbol&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>undefined reference to \`function_name&#39;</span></span></code></pre></div><p>根因：编译时没链接到所需的库。<code>./configure</code> 要加 <code>-l</code> 参数指定库名，或装对应库的开发包。</p><p>排查编译失败的关键是看错误信息里缺的是<strong>头文件</strong>（<code>.h</code>）还是<strong>库文件</strong>（<code>.so</code>）——头文件缺装 <code>-devel</code>/<code>-dev</code>，库文件缺要检查 <code>./configure</code> 的链接参数。</p><h2 id="五、动态库依赖-ldd-与-ldconfig" tabindex="-1">五、动态库依赖：ldd 与 ldconfig <a class="header-anchor" href="#五、动态库依赖-ldd-与-ldconfig" aria-label="Permalink to &quot;五、动态库依赖：ldd 与 ldconfig&quot;">​</a></h2><p>源码编译或二进制部署的软件，运行时报&quot;找不到动态库&quot;：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./app: error while loading shared libraries: libfoo.so.2: cannot open shared object file: No such file or directory</span></span></code></pre></div><p>这是动态库依赖问题。</p><h3 id="用-ldd-看依赖" tabindex="-1">用 ldd 看依赖 <a class="header-anchor" href="#用-ldd-看依赖" aria-label="Permalink to &quot;用 ldd 看依赖&quot;">​</a></h3><p><code>ldd</code> 列出一个可执行文件依赖哪些动态库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ldd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/app/bin/app</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># linux-vdso.so.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libfoo.so.2 =&gt; not found          ← 这行 not found 就是问题</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libc.so.6 =&gt; /lib64/libc.so.6</span></span></code></pre></div><p><code>not found</code> 的库就是缺失的。接下来找这个库装在哪了：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;libfoo.so*&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /opt/libfoo/lib/libfoo.so.2</span></span></code></pre></div><h3 id="让系统找到库-ldconfig" tabindex="-1">让系统找到库：ldconfig <a class="header-anchor" href="#让系统找到库-ldconfig" aria-label="Permalink to &quot;让系统找到库：ldconfig&quot;">​</a></h3><p>库文件在非标准路径下（如 <code>/opt/libfoo/lib</code>），系统默认找不到。两种方式让它被找到：</p><p>方式 1：把库路径加到 ld 配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/opt/libfoo/lib&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ld.so.conf.d/libfoo.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ldconfig</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 刷新动态库缓存</span></span></code></pre></div><p>方式 2：用环境变量（临时）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LD_LIBRARY_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/opt/libfoo/lib</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span></span></code></pre></div><p><code>ldconfig</code> 刷新的是 <code>/etc/ld.so.cache</code>，系统启动时和装新库后都要跑一次。<code>LD_LIBRARY_PATH</code> 只对当前 shell 生效，适合临时测试，不适合写进生产配置。</p><h2 id="六、版本升级导致-abi-不兼容" tabindex="-1">六、版本升级导致 ABI 不兼容 <a class="header-anchor" href="#六、版本升级导致-abi-不兼容" aria-label="Permalink to &quot;六、版本升级导致 ABI 不兼容&quot;">​</a></h2><p>升级某个库后，依赖它的程序跑不起来了——这是 ABI（应用二进制接口）不兼容。常见场景：升级 libstdc++ 后，旧程序报 <code>GLIBCXX_3.4.29 not found</code>。</p><h3 id="排查-2" tabindex="-1">排查 <a class="header-anchor" href="#排查-2" aria-label="Permalink to &quot;排查&quot;">​</a></h3><p>看程序需要哪些符号（symbol）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看应用需要哪些符号版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/app/bin/app</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GLIBC</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># GLIBC_2.28</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># GLIBCXX_3.4.29</span></span></code></pre></div><p>看当前系统提供哪些：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /lib64/libstdc++.so.6</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GLIBCXX</span></span></code></pre></div><p>如果系统提供的符号版本低于程序需要的，就是 ABI 不兼容。</p><h3 id="处理-1" tabindex="-1">处理 <a class="header-anchor" href="#处理-1" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ul><li>系统缺少高版本符号：升级对应的库（但要注意影响全系统）</li><li>之前对某库做了升级或降级导致：回滚那个操作</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看最近的安装/升级记录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL 系可以撤销某次操作</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> undo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">D</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>生产环境对核心库（glibc、libstdc++、openssl）的版本变动要非常谨慎，最好先在测试机验证。</p><h2 id="七、gpg-校验失败" tabindex="-1">七、GPG 校验失败 <a class="header-anchor" href="#七、gpg-校验失败" aria-label="Permalink to &quot;七、GPG 校验失败&quot;">​</a></h2><p>安装时报 GPG key 校验失败：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>warning: Package nginx.rpm is not signed</span></span>
<span class="line"><span>Error: GPG check FAILED</span></span></code></pre></div><p>根因：仓库的 GPG key 没导入，或包确实被篡改。</p><h3 id="处理-2" tabindex="-1">处理 <a class="header-anchor" href="#处理-2" aria-label="Permalink to &quot;处理&quot;">​</a></h3><p>从仓库提供的 URL 导入 key（确认仓库可信的前提下）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://mirrors.aliyun.com/epel/RPM-GPG-KEY-EPEL-9</span></span></code></pre></div><p>或者临时跳过校验（只在确认仓库可信时用，不推荐作为常规做法）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nogpgcheck</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre></div><p>跳过 GPG 校验意味着不验证包的来源和完整性，有安全风险。生产环境应该导入正确的 key 走正常校验，而不是 <code>--nogpgcheck</code> 绕过。</p><h2 id="八、同一台机器多个-python-解释器" tabindex="-1">八、同一台机器多个 Python 解释器 <a class="header-anchor" href="#八、同一台机器多个-python-解释器" aria-label="Permalink to &quot;八、同一台机器多个 Python 解释器&quot;">​</a></h2><p>很多服务器同时存在 <code>python2</code>、<code>python3</code>、<code>/usr/local/bin/python</code>（自己编译的）、<code>/opt/conda/bin/python</code>（Anaconda）。脚本里写 <code>python xxx.py</code> 实际跑的是哪个，完全看 PATH 顺序。</p><h3 id="排查-3" tabindex="-1">排查 <a class="header-anchor" href="#排查-3" aria-label="Permalink to &quot;排查&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 列出 PATH 中所有同名命令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/python</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 看是否软链接到某个具体版本</span></span></code></pre></div><p><code>which -a</code> 会列出 PATH 里所有叫 python 的命令，按优先级排列。<code>/usr/bin/python</code> 可能是个软链接，指向 <code>python3</code> 或 <code>python2</code>，不同发行版默认不同。</p><h3 id="规范" tabindex="-1">规范 <a class="header-anchor" href="#规范" aria-label="Permalink to &quot;规范&quot;">​</a></h3><p>生产脚本写 shebang 时，明确指定版本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/python3.9    # 比 #!/usr/bin/env python 更可靠</span></span></code></pre></div><p><code>#!/usr/bin/env python</code> 会按 PATH 找 python，不同机器 PATH 不一样就可能跑错版本。明确写 <code>/usr/bin/python3.9</code> 能避免这个问题。</p><h2 id="九、卸载的注意事项" tabindex="-1">九、卸载的注意事项 <a class="header-anchor" href="#九、卸载的注意事项" aria-label="Permalink to &quot;九、卸载的注意事项&quot;">​</a></h2><h3 id="apt-purge-删配置" tabindex="-1">apt purge 删配置 <a class="header-anchor" href="#apt-purge-删配置" aria-label="Permalink to &quot;apt purge 删配置&quot;">​</a></h3><p><code>apt purge nginx</code> 不仅卸载程序，还会删 <code>/etc/nginx/</code> 下的全部配置文件。如果机器上有手工调优过的配置，操作前必须先备份：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 卸载前快照</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> czf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backup/nginx-conf-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%Y%m%d</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/nginx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ssl</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 卸载</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> purge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>生产环境的服务配置文件应当统一纳入版本管理系统（Git），机器上的配置只是工作副本。这样即使误执行 purge，从仓库重新拉取即可恢复。</p><h3 id="卸载后依赖残留" tabindex="-1">卸载后依赖残留 <a class="header-anchor" href="#卸载后依赖残留" aria-label="Permalink to &quot;卸载后依赖残留&quot;">​</a></h3><p><code>yum remove nginx</code> 卸载 nginx，但当初装 nginx 时一并装上的依赖包（如 nginx-all-modules）不会自动卸载。要清理这些孤儿包：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> autoremove</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Debian 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> autoremove</span></span></code></pre></div><p><code>autoremove</code> 会清理&quot;当初作为依赖装上、现在没有其他包依赖它&quot;的包。操作前看清楚列表，避免误删。</p><h2 id="故障排查的共同思路" tabindex="-1">故障排查的共同思路 <a class="header-anchor" href="#故障排查的共同思路" aria-label="Permalink to &quot;故障排查的共同思路&quot;">​</a></h2><p>装软件出问题，排查顺序基本固定：</p><ol><li><strong>看报错信息</strong>——是锁、依赖冲突、缺库、还是 GPG。报错信息通常直接指向问题类型。</li><li><strong>查文件归属和包来源</strong>——<code>rpm -qf</code>/<code>dpkg -S</code> 看文件属于哪个包，<code>yum provides</code> 看命令属于哪个包。</li><li><strong>看仓库状态</strong>——<code>yum repolist</code>/<code>apt list</code> 确认仓库是否正常、版本是否符合预期。</li><li><strong>动态库问题用 ldd</strong>——<code>ldd</code> 看缺什么库，<code>ldconfig</code> 刷新缓存。</li><li><strong>核心库操作前评估影响</strong>——glibc、openssl 这类核心库的版本变动影响全系统，生产环境务必先测试。</li></ol><p>下一篇转向计划任务——让机器按时间自动跑命令。</p>`,104)])])}const g=a(t,[["render",l]]);export{r as __pageData,g as default};
